  onFilterChange: (newFilters: Partial<FilterState>) => void;
  onSearch: () => void;
  isLoading: boolean;
  availableLots: string[];
}

const FilterSection: React.FC<FilterSectionProps> = ({ 
  filters, 
  onFilterChange, 
