/**
 * Enhanced fetch with longer timeout and retry logic
 */
const fetchWithRetry = async (url: string, retries: number = 1, timeoutMs: number = 60000): Promise<Response> => {
  for (let i = 0; i <= retries; i++) {
    const controller = new AbortController();
    const id = setTimeout(() => controller.abort(), timeoutMs);

    try {
      console.log(`Fetch attempt ${i + 1} of ${retries + 1}...`);
      const response = await fetch(url, {
        method: 'GET',
        mode: 'cors',
        credentials: 'omit',
        signal: controller.signal,
        cache: 'no-store'
      });
      clearTimeout(id);
      return response;
    } catch (err: any) {
      clearTimeout(id);
      if (i === retries) throw err;
      console.warn(`Attempt ${i + 1} failed, retrying...`, err.message);
    }
  }
  throw new Error('All fetch attempts failed');
};

